#!/usr/bin/env node
// QA Council - Duplicate Function Detection
// Generated by The Engineer (Agent 3). Scans for duplicate function definitions.
// Usage: node duplicate-function-checks.js

var fs = require('fs');
var path = require('path');

var CONFIG = {
  basePath: '/sessions/sleepy-gifted-allen/mnt/site/builder',
  jsFiles: [
    'js/ai-engine.js',
    'js/budget-alignment.js',
    'js/budget-integration.js',
    'js/budget-setup.js',
    'js/budget-tracker.js',
    'js/builder.js',
    'js/doc-generator.js',
    'js/features.js',
    'js/paywall.js',
    'js/stakeholder.js',
    'js/toolkit.js'
  ]
};

var results = [];
var passed = 0;
var failed = 0;
var duplicates = [];

function assert(condition, testName, details) {
  if (condition) {
    console.log('[PASS] ' + testName);
    passed++;
  } else {
    console.log('[FAIL] ' + testName + (details ? ': ' + details : ''));
    failed++;
  }
  results.push({ test: testName, passed: condition, details: details || '' });
}

// ============================================================================
// TEST: Find All Function Definitions
// ============================================================================
function findDuplicateFunctions() {
  console.log('\n--- Scanning for Duplicate Functions ---\n');

  var functionMap = {}; // functionName -> [{ file, line, signature }, ...]

  CONFIG.jsFiles.forEach(function(jsFile) {
    var filePath = path.join(CONFIG.basePath, jsFile);
    if (!fs.existsSync(filePath)) {
      console.log('[SKIP] ' + jsFile + ' (not found)');
      return;
    }

    var content = fs.readFileSync(filePath, 'utf8');
    var lines = content.split('\n');

    // Match function declarations: function name(...) or var name = function(...) or name: function(...)
    var functionRegex = /(?:function\s+(\w+)\s*\(([^)]*)\))|(?:var\s+(\w+)\s*=\s*function\s*\(([^)]*)\))|(?:(\w+)\s*:\s*function\s*\(([^)]*)\))/g;
    var match;

    while ((match = functionRegex.exec(content)) !== null) {
      // Extract function name and parameters
      var name = match[1] || match[3] || match[5];
      var params = match[2] || match[4] || match[6] || '';

      if (!functionMap[name]) {
        functionMap[name] = [];
      }

      // Find line number
      var lineNum = content.substring(0, match.index).split('\n').length;

      functionMap[name].push({
        file: jsFile,
        line: lineNum,
        signature: params ? params.trim() : ''
      });
    }
  });

  // Find duplicates
  var hasDuplicates = false;
  var criticalDuplicates = ['calculateFeasibilityScore', 'recalculateBudgetSummary'];

  for (var funcName in functionMap) {
    if (functionMap[funcName].length > 1) {
      var locations = functionMap[funcName];

      // Skip IIFE internal/external duplicates in the same file (doc-generator.js pattern)
      if (locations.every(function(loc) { return loc.file === 'js/doc-generator.js'; })) {
        console.log('SKIP (same file IIFE pattern): ' + funcName);
        console.log('');
        continue;
      }

      hasDuplicates = true;

      console.log('DUPLICATE FOUND: ' + funcName);
      locations.forEach(function(loc) {
        console.log('  - ' + loc.file + ':' + loc.line);
        console.log('    Parameters: (' + loc.signature + ')');
      });
      console.log('');

      var isCritical = criticalDuplicates.indexOf(funcName) !== -1;
      duplicates.push({
        name: funcName,
        count: locations.length,
        locations: locations,
        critical: isCritical
      });

      var severity = isCritical ? '[P0]' : '[P1]';
      assert(false, severity + ' Duplicate function: ' + funcName, 'Defined in ' + locations.length + ' files');
    }
  }

  if (!hasDuplicates) {
    console.log('No duplicate function definitions found.\n');
    assert(true, 'No duplicate functions detected');
  }

  // Specifically test for the known critical duplicates
  console.log('\n--- Critical Duplicate Function Tests ---\n');

  var knownDuplicates = [
    {
      name: 'calculateFeasibilityScore',
      files: ['js/ai-engine.js', 'js/budget-integration.js'],
      severity: 'P0'
    },
    {
      name: 'recalculateBudgetSummary',
      files: ['js/budget-alignment.js', 'js/budget-tracker.js'],
      severity: 'P0'
    }
  ];

  knownDuplicates.forEach(function(dup) {
    var foundIn = [];
    dup.files.forEach(function(file) {
      var filePath = path.join(CONFIG.basePath, file);
      if (fs.existsSync(filePath)) {
        var content = fs.readFileSync(filePath, 'utf8');
        var nameRegex = new RegExp('\\b' + dup.name + '\\s*[=:]?\\s*(?:function|=)');
        if (nameRegex.test(content)) {
          foundIn.push(file);
        }
      }
    });

    if (foundIn.length > 1) {
      assert(false, dup.severity + ' - ' + dup.name + ' defined in multiple files', 'Found in: ' + foundIn.join(', '));
    } else if (foundIn.length === 1) {
      assert(true, dup.severity + ' - ' + dup.name + ' defined in one file (resolved)');
    } else {
      assert(false, dup.severity + ' - ' + dup.name + ' not found', 'Could not locate function');
    }
  });
}

// ============================================================================
// TEST: Function Signature Consistency
// ============================================================================
function testSignatureConsistency() {
  console.log('\n--- Function Signature Consistency ---\n');

  // For known duplicates, verify their signatures differ or match
  var criticalPairs = [
    {
      name: 'calculateFeasibilityScore',
      file1: 'js/ai-engine.js',
      file2: 'js/budget-integration.js'
    },
    {
      name: 'updateBudgetSummary',
      file1: 'js/budget-alignment.js',
      file2: 'js/budget-tracker.js'
    }
  ];

  criticalPairs.forEach(function(pair) {
    var path1 = path.join(CONFIG.basePath, pair.file1);
    var path2 = path.join(CONFIG.basePath, pair.file2);

    if (!fs.existsSync(path1) || !fs.existsSync(path2)) {
      return;
    }

    var content1 = fs.readFileSync(path1, 'utf8');
    var content2 = fs.readFileSync(path2, 'utf8');

    // Extract function signatures
    var regex = new RegExp('(?:function\\s+' + pair.name + '\\s*\\(([^)]*)\\)|' + pair.name + '\\s*=\\s*function\\s*\\(([^)]*)\\)|' + pair.name + '\\s*:\\s*function\\s*\\(([^)]*)\\))');

    var match1 = regex.exec(content1);
    var match2 = regex.exec(content2);

    if (match1 && match2) {
      var sig1 = match1[1] || match1[2] || match1[3];
      var sig2 = match2[1] || match2[2] || match2[3];

      if (sig1 === sig2) {
        console.log('DUPLICATE FOUND: ' + pair.name + ' has identical signatures in both files');
        console.log('  File 1: (' + sig1 + ')');
        console.log('  File 2: (' + sig2 + ')');
        console.log('');
        assert(false, '[P0] ' + pair.name + ' signatures identical (duplicate!)', 'Both files: (' + sig1 + ')');
      } else {
        console.log('CONFLICT FOUND: ' + pair.name + ' has different signatures in both files');
        console.log('  File 1: (' + sig1 + ')');
        console.log('  File 2: (' + sig2 + ')');
        console.log('');
        assert(false, '[P0] ' + pair.name + ' signatures differ (both versions exist!)', 'Conflict between implementations');
      }
    } else if (match1 || match2) {
      var found = match1 ? pair.file1 : pair.file2;
      console.log('RESOLVED: ' + pair.name + ' found in only one file');
      console.log('  Location: ' + found);
      console.log('');
      assert(true, '[RESOLVED] ' + pair.name + ' no longer duplicated');
    }
  });
}

// ============================================================================
// RUN ALL TESTS
// ============================================================================
console.log('\n======================================');
console.log('QA Council: Duplicate Function Checks');
console.log('======================================');
console.log('Base Path: ' + CONFIG.basePath);
console.log('');

findDuplicateFunctions();
testSignatureConsistency();

console.log('\n======================================');
console.log('Results: ' + passed + ' passed, ' + failed + ' failed');
if (duplicates.length > 0) {
  console.log('Duplicates Found: ' + duplicates.length);
}
console.log('======================================\n');

// Write results to JSON
var outputPath = path.join(path.dirname(process.argv[1]), 'duplicate-results.json');
fs.writeFileSync(outputPath, JSON.stringify({
  target: 'district-builder',
  timestamp: new Date().toISOString(),
  passed: passed,
  failed: failed,
  total: passed + failed,
  duplicatesFound: duplicates.length,
  duplicates: duplicates,
  results: results
}, null, 2));

console.log('Results written to: duplicate-results.json');
process.exit(failed > 0 ? 1 : 0);
